import numpy as np

# {The backbone idea in the provided algorithms is evaluating potential visits by combining spatial proximities with dynamic adjustments based on clustered densities or multiplicative visibility factors.}

# {The new algorithm leverages a predict-and-adapt strategy emphasizing future customer impact and harmonious route interference by computing the influence of each site on evolving network balance metrics.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    node_scores = []
    avg_truck_pos = np.mean(all_truck_pos, axis=0)

    for idx, customer in enumerate(unvisited_customers):
        distance_to_current_truck = np.linalg.norm(cur_truck_pos - customer)
        influence_factor = 1 / (1 + np.linalg.norm(customer - avg_truck_pos))
        network_impact = np.sum([np.linalg.norm(customer - other_customer) for other_customer in unvisited_customers])

        score = distance_to_current_truck * influence_factor / max(1, network_impact)

        node_scores.append(score)

    best_node = np.argmin(node_scores)
    return best_node

import numpy as np

# {The algorithm selects the next customer by prioritizing those that are closer to the current truck position and have a higher average distance to all other trucks, aiming to minimize downtime and overlap.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    scores = []
    for idx, customer in enumerate(unvisited_customers):
        distance_to_truck = np.linalg.norm(cur_truck_pos - customer)
        average_distance_to_other_trucks = np.mean([np.linalg.norm(truck_pos - customer) for truck_pos in all_truck_pos])
        scores.append(distance_to_truck - average_distance_to_other_trucks)

    best_node = np.argmin(scores)
    return best_node

import numpy as np

# Backbone idea: Evaluate potential next nodes by considering both spatial distance and a secondary factor related to customer dynamics.

# {The algorithm assigns priority to customers based on their proximity to multiple trucks, selecting nodes that are centrally located among multiple trucks to spread the workload and dynamically adapt to changes.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    weights = []
    for idx, customer in enumerate(unvisited_customers):
        distance = np.linalg.norm(cur_truck_pos - customer)
        proximity_weight = sum([1 / (1 + np.linalg.norm(truck_pos - customer)) for truck_pos in all_truck_pos])
        weights.append(distance * proximity_weight)

    best_node = np.argmin(weights)
    return best_node
